  1	import { type Ref, useState } from 'react';
  2	
  3	import {
  4	  MenuToggle,
  5	  type MenuToggleElement,
  6	  Select,
  7	  SelectList,
  8	  SelectOption,
  9	  ToolbarGroup,
 10	  ToolbarItem,
 11	} from '@patternfly/react-core';
 12	
 13	import { FilterFromDef } from './FilterFromDef';
 14	import type { MetaFilterProps } from './types';
 15	
 16	/**
 17	 * This is an implementation of [<font>``PatternFly 4`` attribute-value filter</font>](https://www.patternfly.org/v4/demos/filters/design-guidelines/#attribute-value-filter) pattern,
 18	 * extended to use any filter matching FilterTypeProps interface (not only enum based selection but also free text, boolean switch and grouped enum based).
 19	 *
 20	 * [<img src="static/media/src/components-stories/assets/github-logo.svg"><i class="fi fi-brands-github">
 21	 * <font color="green">View component source on GitHub</font>](https://github.com/kubev2v/forklift-console-plugin/blob/main/packages/common/src/components/FilterGroup/AttributeValueFilter.tsx)
 22	 *
 23	 * @see FilterTypeProps
 24	 */
 25	export const AttributeValueFilter = ({
 26	  fieldFilters,
 27	  onFilterUpdate,
 28	  resolvedLanguage = 'en',
 29	  selectedFilters = {},
 30	  supportedFilterTypes,
 31	}: MetaFilterProps) => {
 32	  const [currentFilter, setCurrentFilter] = useState(fieldFilters?.[0]);
 33	  const [isOpen, setIsOpen] = useState(false);
 34	
 35	  const selectOptionToFilter = (selectedValue: string) =>
 36	    fieldFilters.find(({ label }) => label === selectedValue) ?? currentFilter;
 37	
 38	  const onToggleClick = () => {
 39	    setIsOpen((prev) => !prev);
 40	  };
 41	
 42	  const toggle = (toggleRef: Ref<MenuToggleElement>) => (
 43	    <MenuToggle ref={toggleRef} onClick={onToggleClick} isExpanded={isOpen} isFullWidth>
 44	      {currentFilter.label}
 45	    </MenuToggle>
 46	  );
 47	
 48	  const onSelect = (value?: string) => {
 49	    if (value) {
 50	      setCurrentFilter(selectOptionToFilter(value));
 51	    }
 52	    setIsOpen((prev) => !prev);
 53	  };
 54	
 55	  const renderOptions = () => {
 56	    return fieldFilters.map(({ label, resourceFieldId }) => (
 57	      <SelectOption key={resourceFieldId} value={label}>
 58	        {label}
 59	      </SelectOption>
 60	    ));
 61	  };
 62	
 63	  return (
 64	    <ToolbarGroup variant="filter-group">
 65	      <ToolbarItem>
 66	        {/* This select is different from most and cannot use the common Select */}
 67	        {/* eslint-disable-next-line no-restricted-syntax */}
 68	        <Select
 69	          role="menu"
 70	          aria-label={'Select Filter'}
 71	          isOpen={isOpen}
 72	          selected={currentFilter?.label}
 73	          onSelect={(_ev, value) => {
 74	            onSelect(String(value));
 75	          }}
 76	          onOpenChange={(nextOpen: boolean) => {
 77	            setIsOpen(nextOpen);
 78	          }}
 79	          toggle={toggle}
 80	          shouldFocusToggleOnSelect
 81	          shouldFocusFirstItemOnOpen={false}
 82	          isScrollable
 83	          popperProps={{
 84	            appendTo: document.body,
 85	            direction: 'down',
 86	            enableFlip: true,
 87	          }}
 88	        >
 89	          <SelectList>{renderOptions()}</SelectList>
 90	        </Select>
 91	      </ToolbarItem>
 92	
 93	      {fieldFilters.map(({ filterDef, label, resourceFieldId }) => (
 94	        <FilterFromDef
 95	          key={resourceFieldId}
 96	          {...{
 97	            filterDef,
 98	            FilterType: supportedFilterTypes[filterDef.type],
 99	            label,
100	            onFilterUpdate,
101	            resolvedLanguage,
102	            resourceFieldId,
103	            selectedFilters,
104	            showFilter: currentFilter?.resourceFieldId === resourceFieldId,
105	          }}
106	        />
107	      ))}
108	    </ToolbarGroup>
109	  );
110	};

